Here’s an example React component using Supabase to fetch and display posts from Genjutsu. First, ensure you have the Supabase client installed:
bash
npm install @supabase/supabase-js


Then, use the following code to fetch and render posts:
javascript
import { useEffect, useState } from 'react';
import { createClient } from '@supabase/supabase-js';

const supabaseUrl = 'YOUR_SUPABASE_URL';
const supabaseKey = 'YOUR_SUPABASE_KEY';
const supabase = createClient(supabaseUrl, supabaseKey);

function PostList() {
  const [posts, setPosts] = useState([]);

  useEffect(() => {
    const fetchPosts = async () => {
      const { data, error } = await supabase
        .from('posts')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) console.error('Error fetching posts:', error);
      else setPosts(data);
    };

    fetchPosts();
  }, []);

  return (
    <div className="space-y-4">
      {posts.map((post) => (
        <div key={post.id} className="p-4 border rounded-lg">
          <h3 className="font-bold">{post.title}</h3>
          <p className="text-gray-600">{post.content}</p>
          <p className="text-sm text-gray-400">Expires in {calculateTimeRemaining(post.created_at)}</p>
        </div>
      ))}
    </div>
  );
}

function calculateTimeRemaining(createdAt) {
  const createdTime = new Date(createdAt).getTime();
  const now = new Date().getTime();
  const diffHours = Math.floor((24 * 60 * 60 * 1000 - (now - createdTime)) / (60 * 60 * 1000));
  return `${diffHours} hours`;
}

Replace `YOUR_SUPABASE_URL` and `YOUR_SUPABASE_KEY` with your Supabase project details.
